"""
MKT Original Language Commentary — Psalms chapters 28–33
Run: python3 scripts/zc-original-psalms-28-33.py

Source data used:
- data/interlinear/psalms.json
- data/translation/glossary-hebrew.json
- data/translation/draft/mediating/psalms.json (MKT text)

Key decisions in this range:
- Ps 28:8 māshîaḥ: "anointed one" — this is the Messianic title, though contextually
  it refers to David; carried forward as one of the recurring "anointed one" markers.
- Ps 29: The "Voice of the LORD" (qôl YHWH) appears 7 times — a liturgical refrain.
  The psalm likely subverts Baal-storm theology (Ugaritic Baal texts describe Baal's
  voice as thunder). Calling YHWH "God of glory" (ʾêl hakkābôd) is unique in the Psalter.
- Ps 30: "Dedication of the Temple" superscription uses ḥanukkāh — the same word as
  the Feast of Dedication (John 10:22). The psalm's movement from prosperity to crisis
  to rescue is the pattern of the Psalter's theodicy.
- Ps 31:5: "Into your hand I commit my spirit" (bĕyādĕkā ʾapqîd rûḥî) — the exact
  phrase Jesus quotes from the cross (Luke 23:46, citing LXX). The rûaḥ (spirit/breath)
  as the innermost self committed into divine custody.
- Ps 32:1-2: Paul quotes these verses in Romans 4:7-8 as the scriptural definition of
  justification by faith. The three terms (transgression/pesha, sin/ḥaṭṭāʾt,
  iniquity/ʿāwōn) are the full vocabulary of human guilt; the verbs (carried/forgiven,
  covered, not-reckoned) are the vocabulary of divine remedy.
- Ps 33:6: Creation by the divine word (dĕbar YHWH) and breath (rûaḥ pîw) — the
  proto-Logos theology that John 1:1-3 develops christologically.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    """Merge new_data into existing without overwriting present entries."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 28–33 — covers the Davidic lament-to-praise (Ps 28),
#   the qôl YHWH storm-theophany hymn subverting Baal theology (Ps 29), the Hanukkah
#   dedication psalm (Ps 30), the trust psalm whose v5 becomes Jesus' final breath on
#   the cross (Ps 31), the penitential/justification psalm cited by Paul in Rom 4 (Ps 32),
#   and the anonymous creation-by-word hymn (Ps 33).
# CHANGE? If data/commentary/mkt-original/psalms.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json')); print([len(d.get(str(c),{})) for c in range(28,34)])"

PSALMS = {
  "28": {
    "1": '<p><strong>צוּרִי אַל-תֶּחֱרַשׁ מִמֶּנִּי</strong> (<em>ṣûrî ʾal-teḥĕrash mimmenî</em>, "my Rock, do not be deaf to me") — <em>ḥārash</em>: to be deaf or silent. Divine silence experienced as deafness — the unanswered prayer feels like a stone wall. The appeal to <em>ṣûr</em> (rock/cliff) is precisely because rocks do not move; the Psalmist asks the immovable one not to be unmovable toward him. <strong>נִמְשַׁלְתִּי עִם-יֹורְדֵי בוֹר</strong> (<em>nimshaltî ʿim-yôrĕdê bôr</em>, "I will be like those who go down to the pit") — <em>bôr</em>: a cistern, a pit — by extension the grave and underworld. Divine silence = death, because only the living praise God (Ps 30:9).</p>',
    "2": '<p><strong>בְּנָשְׂאִי יָדַי אֶל-דְּבִיר קָדְשֶׁךָ</strong> (<em>bĕnāśĕʾî yāday ʾel-dĕbîr qodshekā</em>, "as I lift my hands toward your Most Holy Place") — <em>dĕbîr</em>: the inner chamber, the Holy of Holies — the back room of the temple (from <em>dābar</em>: that which is behind). The ritual lifting of hands was a standard prayer posture (1 Tim 2:8). Solomon prays that God would hear prayers directed toward this place even from a distance (1 Kgs 8:29-30).</p>',
    "3": '<p><strong>הַמְדַבְּרִים שָׁלוֹם עִם-רֵעֵיהֶם</strong> (<em>hĕmĕdabbĕrîm shālôm ʿim-rêʿêhem</em>, "who speak peace to their neighbors") — the wicked who use <em>shālôm</em> (peace) as a social greeting while harboring <strong>רָעָה בִּלְבָבָם</strong> (<em>rāʿāh bilĕbābām</em>, "evil in their hearts"). The heart-speech contrast: social performance of <em>shālôm</em> conceals interior hostility. The two-tongue motif recurs in Ps 12:2-3 and Jas 3:10. The <em>lêb</em> (heart/mind) as the true location of the self, unmasked by God (Ps 7:9).</p>',
    "4": '<p><strong>תֶּן-לָהֶם כְּפָעֳלָם</strong> (<em>ten-lāhem kĕpoʿŏlām</em>, "Pay them back for what they have done") — <em>pōʿal</em> (deed, work — from <em>pāʿal</em>: to work, to do): a different word from <em>maʿăśeh</em> (artistic work); <em>pōʿal</em> focuses on the act as a moral deed. The imprecation follows the lex talionis logic: the return is proportional to the <em>kĕpoʿŏlām</em> (according to their doing). The prayer for divine judgment is not vengeance-seeking but covenant appeal — God is the judge who must respond consistently to wickedness.</p>',
    "5": '<p><strong>כִּי לֹא יָבִינוּ אֶל-פְּעֻלֹּת יְהוָה</strong> (<em>kî lōʾ yābînû ʾel-pĕʿullōt YHWH</em>, "Because they take no account of the LORD\'s works") — <em>bîn</em>: to perceive, discern, pay attention to — the failure is moral inattention to what is visible. <em>Pĕʿullōt YHWH</em> (the LORD\'s deeds): the deeds of God in history that demand theological interpretation. <strong>יֶהֶרְסֵם וְלֹא יִבְנֵם</strong> (<em>yehĕrsêm wĕlōʾ yibnêm</em>, "he will pull them down and not rebuild them") — <em>hāras</em> (to demolish) vs <em>bānāh</em> (to build): total and unreversed demolition.</p>',
    "6": '<p><strong>בָּרוּךְ יְהוָה</strong> (<em>bārûk YHWH</em>, "Praise the LORD!") — the abrupt reversal from petition (vv1-5) to praise (vv6-9). <strong>כִּי שָׁמַע קוֹל תַּחֲנוּנָי</strong> (<em>kî shāmaʿ qôl taḥanûnāy</em>, "for he has heard my cry for mercy") — <em>taḥanûn</em>: supplication, plea for grace (from <em>ḥānan</em>: to be gracious). The perfect tense <em>shāmaʿ</em> (he heard) registers certainty of divine response before it is visibly confirmed — faith that the prayer has been received.</p>',
    "7": '<p><strong>יְהוָה עֻזִּי וּמָגִנִּי</strong> (<em>YHWH ʿuzzî ûmāginnî</em>, "The LORD is my strength and my shield") — <em>ʿōz</em> (strength/power — same word as Ps 8:2 where it also means "praise") and <em>māgên</em> (the small personal shield). <strong>וַיַּעֲלֹז לִבִּי</strong> (<em>wayyaʿălōz libbî</em>, "my heart leaps for joy") — <em>ʿālaz</em>: to exult, to leap for joy — a physical, exuberant rejoicing (used of the earth rejoicing, Ps 96:12). The joy is bodily, not merely cognitive.</p>',
    "8": '<p><strong>יְהוָה עֹז-לָמוֹ וּמָעוֹז יְשׁוּעוֹת מְשִׁיחוֹ</strong> (<em>YHWH ʿōz-lāmô ûmāʿôz yĕshûʿôt mĕshîḥô</em>, "The LORD is the strength of his people; he is the saving fortress of his anointed one") — <em>mĕshîaḥ</em>: his anointed one. The Davidic king is the LORD\'s <em>māshîaḥ</em> (Messiah), and the protection of the people flows through the anointed. <em>Māʿôz yĕshûʿôt</em>: "fortress of salvations" — the multiple acts of rescue collected under this image. For the NT, the title <em>māshîaḥ</em> makes this the language of the one through whom all divine saving strength reaches the people.</p>',
    "9": '<p><strong>וּרְעֵם וְנַשְּׂאֵם עַד-הָעוֹלָם</strong> (<em>ûrĕʿêm wĕnassĕʾêm ʿad-hāʿôlām</em>, "be their shepherd and carry them forever") — two parental/pastoral verbs: <em>rāʿāh</em> (to shepherd, to tend) and <em>nāśāʾ</em> (to carry, to bear — as a parent carries a child, Deut 1:31). The combination of shepherding and carrying is the image of the LORD who both leads and physically bears the people. <em>ʿad-hāʿôlām</em>: forever — the eternal scope of the carrying. Jesus as the Good Shepherd who carries the lost sheep home (Luke 15:5) draws on this pastoral register.</p>',
  },
  "29": {
    "1": '<p><strong>הָבוּ לַיהוָה בְּנֵי אֵלִים</strong> (<em>hābû laYHWH bĕnê ʾêlîm</em>, "Ascribe to the LORD, O heavenly beings") — <em>bĕnê ʾêlîm</em>: "sons of God/divine beings" — the heavenly council that surrounds the divine throne (Job 1:6; Ps 82:1, 6). The psalm opens by commanding the divine council to worship YHWH — not Israel, but the celestial assembly itself. This is a remarkable claim about YHWH\'s supremacy in the heavenly realm.</p>',
    "2": '<p><strong>הָבוּ לַיהוָה כְּבוֹד שְׁמוֹ</strong> (<em>hābû laYHWH kĕbôd shĕmô</em>, "Give the LORD the glory due his name") — <em>kābôd</em>: weight, honor, splendor — the overwhelming presence of God. <strong>הִשְׁתַּחֲווּ לַיהוָה בְּהַדְרַת-קֹדֶשׁ</strong> (<em>hishtaḥăwû laYHWH bĕhadrat-qōdesh</em>, "Worship the LORD in the splendor of his holiness") — <em>hadrat-qōdesh</em>: a debated phrase; "splendor/glory of holiness" or "holy attire/array." Either way, worship is not casual but appropriately clothed in what holiness requires.</p>',
    "3": '<p><strong>קוֹל יְהוָה עַל-הַמָּיִם</strong> (<em>qôl YHWH ʿal-hammāyim</em>, "The voice of the LORD is over the waters") — the first of seven <em>qôl YHWH</em> (Voice of the LORD) occurrences in vv3-9, functioning as a liturgical refrain. <strong>אֵל-הַכָּבוֹד הִרְעִים</strong> (<em>ʾêl-hakkābôd hirʿîm</em>, "the God of glory thunders") — <em>ʾêl hakkābôd</em>: "the God of glory" — a unique phrase in the Psalter. Stephen cites it in Acts 7:2 ("The God of glory appeared to our father Abraham"). The title identifies YHWH as the possessor of the divine <em>kābôd</em> (weight/presence) that the divine council was commanded to ascribe to him.</p>',
    "4": '<p><strong>קוֹל-יְהוָה בַּכֹּחַ</strong> (<em>qôl-YHWH bakkōaḥ</em>, "The voice of the LORD is powerful") — <em>kōaḥ</em>: strength, force, power — the raw physical energy of the divine voice (thunder). <strong>קוֹל יְהוָה בֶּהָדָר</strong> (<em>qôl YHWH behādār</em>, "the voice of the LORD is majestic") — <em>hādār</em>: splendor, majesty, beauty — the aesthetic dimension alongside brute force. These two terms (power + majesty) form the Ugaritic storm-god Baal\'s vocabulary, here entirely reassigned to YHWH — the theological polemic is embedded in the word-choice.</p>',
    "5": '<p><strong>קוֹל יְהוָה שֹׁבֵר אֲרָזִים</strong> (<em>qôl YHWH shōbêr ʾărāzîm</em>, "The voice of the LORD shatters the cedars") — <em>shābar</em>: to shatter, to break into pieces. The cedars of Lebanon (<em>ʾarzê hallĕbānôn</em>) were the largest, most permanent trees in the ancient world — symbols of royal power and permanence (Isa 2:13; Ezek 31:3). If the divine voice shatters what no human force can break, it is omnipotent.</p>',
    "6": '<p><strong>וַיַּרְקִידֵם כְּמוֹ-עֵגֶל</strong> (<em>wayyarqîdêm kĕmô-ʿêgel</em>, "He makes Lebanon skip like a calf") — <em>rāqad</em>: to skip, to dance, to leap (the joy-dance). The mountain-shattering force that breaks cedars causes the mountains to dance like calves. <em>Sîryôn</em> (Sirion): the Phoenician name for Mount Hermon (Deut 3:9). The wild ox (<em>rĕʾêm</em>) was the most uncontrollable animal known in the ancient world — yet it "skips" before the divine voice.</p>',
    "7": '<p><strong>קוֹל יְהוָה חֹצֵב לַהֲבוֹת אֵשׁ</strong> (<em>qôl YHWH ḥōṣêb lahăbôt ʾêsh</em>, "The voice of the LORD strikes with flashes of lightning") — <em>ḥāṣab</em>: to hew, to cut out, to carve — the lightning as if chiseled from the storm. <em>Lahăbôt ʾêsh</em>: "flames of fire" — lightning as fire-flames cut from the sky. The creative/destructive ambiguity: the same verb used for stonecutting is used for the lightning-bolt, as if God is a craftsman cutting fire from the sky.</p>',
    "8": '<p><strong>קוֹל יְהוָה יָחִיל מִדְבָּר</strong> (<em>qôl YHWH yāḥîl midbār</em>, "The voice of the LORD shakes the wilderness") — <em>ḥûl</em>: to writhe, to tremble, to be in labor — the same verb used in v9 for the deer writhing in labor. The wilderness (<em>midbār</em>) itself writhes at the divine voice. <em>Midbār qādesh</em>: the wilderness of Kadesh — the southern region through which Israel wandered, now the scene of theophanic power.</p>',
    "9": '<p><strong>קוֹל יְהוָה יְחוֹלֵל אַיָּלוֹת</strong> (<em>qôl YHWH yĕḥôlêl ʾayyālôt</em>, "The voice of the LORD causes the deer to writhe in labor") — <em>yāḥal</em> (polel: to cause to writhe/bring to birth): the divine voice triggers labor contractions in the deer. The same voice that breaks cedars also determines the moment of birthing — control over both the large and the small. <strong>וּבְהֵיכָלוֹ כֻּלּוֹ אֹמֵר כָּבוֹד</strong> (<em>ûbĕhêkālô kullô ʾōmêr kābôd</em>, "in his temple all cry, \'Glory!\'") — the seventh and final <em>qôl YHWH</em> produces the worshiping cry: <em>kābôd</em> (glory). The heavenly assembly responds with the one word that encapsulates all ascription.</p>',
    "10": '<p><strong>יְהוָה לַמַּבּוּל יָשָׁב</strong> (<em>YHWH lammabbûl yāshāb</em>, "The LORD sat enthroned over the Flood") — <em>mabbûl</em>: the Noahic flood — the only use of this specific word in the Psalter. It is the exclusive word Genesis uses for Noah\'s flood (Gen 6-9), not the generic flood-word (<em>shéṭeph</em>). YHWH was enthroned above the primordial chaos-flood — the creator was not threatened but in sovereign session above it. <strong>וַיֵּשֶׁב יְהוָה מֶלֶךְ לְעוֹלָם</strong> (<em>wayyêsheb YHWH melek lĕʿôlām</em>, "the LORD sits enthroned as King forever") — the one who sat above the primordial flood is the one who sits forever.</p>',
    "11": '<p><strong>יְהוָה עֹז לְעַמּוֹ יִתֵּן</strong> (<em>YHWH ʿōz lĕʿammô yittên</em>, "The LORD gives strength to his people") — the same <em>ʿōz</em> (strength) that the heavenly beings were commanded to ascribe to YHWH (v1) is now given by YHWH to his people. The divine strength is not hoarded but distributed. <strong>יְהוָה יְבָרֵךְ אֶת-עַמּוֹ בַשָּׁלוֹם</strong> (<em>YHWH yĕbārêk ʾet-ʿammô bashshālôm</em>, "the LORD blesses his people with peace") — the storm-theophany psalm ends with <em>shālôm</em> (peace, wholeness). The God whose voice shatters cedars and triggers labor blesses his people with peace. The power is the foundation of the peace: only the one mightier than every storm can give true <em>shālôm</em>.</p>',
  },
  "30": {
    "1": '<p>The superscription reads <strong>שִׁיר חֲנֻכַּת הַבַּיִת לְדָוִד</strong> (<em>shîr ḥanukkāt habbayit lĕdāwid</em>, "A Song for the Dedication of the Temple, of David") — <em>ḥanukkāh</em>: dedication (from <em>ḥānak</em>: to initiate, to dedicate). The same word as the Feast of Dedication (Hanukkah) in John 10:22. The verb <strong>אֲרוֹמִמְךָ</strong> (<em>ʾărômimkā</em>, "I exalt you") — <em>rûm</em> (hiphil: to lift up, to exalt): the Psalmist "lifts up" God in response to God having "lifted him up" — <strong>דִּלִּיתָנִי</strong> (<em>dillîtānî</em>, "you have lifted me up") from <em>dālāh</em>: to draw up (as drawing water from a well). The rescue is like drawing someone up from a cistern.</p>',
    "2": '<p><strong>אֱלֹהַי שִׁוַּעְתִּי אֵלֶיךָ וַתִּרְפָּאֵנִי</strong> (<em>ʾĕlōhay shiwwaʿtî ʾêlêkā wattirpāʾênî</em>, "I cried to you for help, and you healed me") — <em>shāwaʿ</em>: to cry for help (same root as the prayer-cry in Ps 28:2); <em>rāpāʾ</em>: to heal. The healing may be literal recovery from illness or a metaphor for deliverance from life-threatening danger (v3 suggests near-death). The divine name <em>ʾĕlōhay</em> (my God) — the first-person possessive relationship as the ground for the cry.</p>',
    "3": '<p><strong>יְהוָה הֶעֱלִיתָ מִן-שְׁאוֹל נַפְשִׁי</strong> (<em>YHWH heʿĕlîtā min-shĕʾôl napshî</em>, "LORD, you brought my soul up from the realm of the dead") — <em>shĕʾôl</em>: the underworld, the comprehensive OT term for the abode of the departed. <strong>חִיִּיתַנִי מִיּוֹרְדֵי-בוֹר</strong> (<em>ḥiyyîtanî miyôrĕdê-bôr</em>, "you restored my life from among those who descend to the pit") — <em>bôr</em>: cistern/pit (as in Ps 28:1) — a second term for the underworld focused on its depth and darkness. <em>Ḥāyāh</em> (piel: to keep alive, to give life): God preserving the Psalmist from joining the descent.</p>',
    "4": '<p><strong>זַמְּרוּ לַיהוָה חֲסִידָיו</strong> (<em>zammĕrû laYHWH ḥăsîdāyw</em>, "Sing praises to the LORD, O you his faithful ones") — <em>zāmar</em>: to make music with instruments — the word behind <em>mizmôr</em> (psalm). <em>Ḥăsîdîm</em>: the faithful/loyal ones — the recipients of God\'s <em>ḥesed</em> (covenant love) who in turn are loyal to him. <strong>לְזֵכֶר קָדְשׁוֹ</strong> (<em>lĕzêker qodshô</em>, "and give thanks to his holy name") — <em>zêker</em>: memory, memorial — the "memory of his holiness" as what is acknowledged in thanksgiving.</p>',
    "5": '<p><strong>כִּי רֶגַע בְּאַפּוֹ חַיִּים בִּרְצוֹנוֹ</strong> (<em>kî regaʿ bĕʾappô ḥayyîm birṣônô</em>, "For his anger lasts only a moment, but his favor lasts a lifetime") — <em>regaʿ</em>: a moment, an instant — the briefest possible time unit. <em>ʾAp</em> (nostril/anger) contrasted with <em>rāṣôn</em> (favor, pleasure, delight). <strong>לָעֶרֶב יָלִין בֶּכִי וְלַבֹּקֶר רִנָּה</strong> (<em>lāʿereb yālîn bekî wĕlabbōqer rinnāh</em>, "weeping may remain through the night, but joy arrives with the morning") — <em>yālîn</em>: to lodge, to spend the night as a temporary guest. Weeping spends the night but is gone by morning; <em>rinnāh</em> (the ringing shout of joy) comes with dawn.</p>',
    "6": '<p><strong>וַאֲנִי אָמַרְתִּי בְשַׁלְוִי</strong> (<em>waʾănî ʾāmartî bĕshalwî</em>, "When I was prosperous, I said") — <em>shalwāh</em>: ease, tranquility, prosperity. The Psalmist\'s confession: prosperity breeds presumption. <strong>בַּל-אֶמּוֹט לְעוֹלָם</strong> (<em>bal-ʾemmôṭ lĕʿôlām</em>, "I will never be shaken") — <em>māṭ</em>: to totter, to be shaken, to slip. The confident claim of permanent stability — precisely the kind of claim that invites divine testing (vv7b-10). The false security of prosperity not grounded in divine favor.</p>',
    "7": '<p><strong>יְהוָה בִּרְצוֹנְךָ הֶעֱמַדְתָּה לְהַרְרִי-עֹז</strong> (<em>YHWH birṣônĕkā heʿĕmadtāh lĕharrî-ʿōz</em>, "By your favor, LORD, you had made my mountain stand firm") — the Psalmist now acknowledges what he failed to see in v6: the stability was not inherent but the product of divine <em>rāṣôn</em> (favor). <strong>הִסְתַּרְתָּ פָנֶיךָ הָיִיתִי נִבְהָל</strong> (<em>histartā pānêkā hāyîtî nibhāl</em>, "when you hid your face, I was terrified") — the theology of the hidden God: <em>hester pānim</em> (hiding of the face) = YHWH withdrawing active presence. <em>Bāhal</em> (niphal: to be terrified): the consequence of divine withdrawal is existential dismay.</p>',
    "8": '<p><strong>אֵלֶיךָ יְהוָה אֶקְרָא</strong> (<em>ʾêlêkā YHWH ʾeqrāʾ</em>, "To you, LORD, I called out") — the natural response to the divine face-hiding is not despair but prayer. <em>Qārāʾ</em> (to call, to cry out): the same call of vv2-3 that was heard and healed. The Psalmist did not turn to other sources of help when the divine face was hidden; he called more urgently to the one who hid it.</p>',
    "9": '<p><strong>מַה-בֶּצַע בְּדָמִי</strong> (<em>māh-beṣaʿ bĕdāmî</em>, "What is gained if I die?") — <em>beṣaʿ</em>: gain, profit (often of commercial gain). The argument from divine interest: what does God gain from the Psalmist\'s death? <strong>הֲיוֹדֶה עָפָר אֱמִתֶּךָ</strong> (<em>hăyôdeh ʿāpār ʾĕmittekā</em>, "Can the dust praise you? Can it proclaim your faithfulness?") — <em>ʿāpār</em> (dust): what the dead return to (Gen 3:19). The implicit argument: the living praise; the dead are silent. God\'s interest in his own glory is best served by keeping the Psalmist alive — not manipulation but the logic of covenant.</p>',
    "10": '<p><strong>שְׁמַע-יְהוָה וְחָנֵּנִי</strong> (<em>shĕmaʿ-YHWH wĕḥonnênî</em>, "Hear me, LORD, and have mercy on me!") — <em>ḥānan</em>: to be gracious, to show mercy/favor (same root as <em>taḥanûn</em> in Ps 28:2). The plea for <em>ḥēn</em> (grace): unearned divine favor. <strong>יְהוָה הֱיֵה-עֹזֵר לִי</strong> (<em>YHWH hĕyêh-ʿōzêr lî</em>, "LORD, be my helper!") — the simple, direct appeal in the moment of need.</p>',
    "11": '<p><strong>הָפַכְתָּ מִסְפְּדִי לְמָחוֹל לִי</strong> (<em>hāpaktā mispĕdî lĕmāḥôl lî</em>, "You have turned my mourning into dancing") — <em>hāpak</em>: to turn, to overturn, to reverse — the same reversal-word used for the overturning of Sodom (Gen 19:25). <em>Mispēd</em>: mourning, formal lamentation. <em>Māḥôl</em>: circle-dancing (from <em>ḥûl</em>: to whirl in circles) — exuberant communal celebration. <strong>פִּתַּחְתָּ שַׂקִּי וַתְּאַזְּרֵנִי שִׂמְחָה</strong> (<em>pittaḥtā śaqqî wattĕʾazzĕrênî śimḥāh</em>, "you have removed my sackcloth and clothed me with joy") — <em>śaq</em>: sackcloth — the rough mourning-garment; <em>śimḥāh</em> (joy) as the new garment. Joy as something worn, not merely felt.</p>',
    "12": '<p><strong>לְמַעַן יְזַמֶּרְךָ כָבוֹד וְלֹא יִדֹּם</strong> (<em>lĕmaʿan yĕzammĕrĕkā kābôd wĕlōʾ yiddōm</em>, "so that my spirit may sing your praise and not be silent") — <em>kābôd</em> here may mean "my honor/my soul" (the internal, honored self) rather than "glory." <em>Yiddōm</em> (to be silent, to be still): the counterpart to the silence of death (v9). The rescued soul cannot be silent — silence is for the dead. <strong>יְהוָה אֱלֹהַי לְעוֹלָם אוֹדֶךָּ</strong> (<em>YHWH ʾĕlōhay lĕʿôlām ʾôdekā</em>, "O LORD my God, I will give you thanks forever") — the closing vow: forever-praise as the response to the forever-favor of v5.</p>',
  },
  "31": {
    "1": '<p><strong>בְּךָ יְהוָה חָסִיתִי</strong> (<em>bĕkā YHWH ḥāsîtî</em>, "In you, LORD, I take refuge") — <em>ḥāsāh</em>: to take refuge, to seek shelter (as under the wings of a parent bird, Ps 57:1). The perfect tense of settled trust: "I have taken refuge and remain there." <strong>בְּצִדְקָתְךָ פַלְּטֵנִי</strong> (<em>bĕṣidqātĕkā pallĕṭênî</em>, "rescue me by your righteousness") — <em>ṣĕdāqāh</em>: righteousness, covenant-faithfulness. The rescue is grounded in the LORD\'s own covenantal integrity — not in the Psalmist\'s merit. God\'s righteousness means he must rescue those who trust in him, because his covenant commits him to it.</p>',
    "2": '<p><strong>הַטֵּה אֵלַי אָזְנְךָ מְהֵרָה הַצִּילֵנִי</strong> (<em>haṭṭeh ʾêlay ʾāznĕkā mĕhêrāh haṣṣîlênî</em>, "Turn your ear to me; quickly rescue me") — <em>nāṭāh</em> (hiphil: to incline/bend down to hear a faint voice). <em>Mĕhêrāh</em>: quickly, speedily — urgency. <strong>לְצוּר-מָעוֹז לְבֵית מְצוּדוֹת לְהוֹשִׁיעֵנִי</strong> — the cluster of spatial metaphors: <em>ṣûr</em> (rock/cliff), <em>māʿôz</em> (stronghold), <em>bêt mĕṣûdôt</em> (house of fortresses) — layered protection: rock → fortress → fortified building within the fortress.</p>',
    "3": '<p><strong>כִּי-סַלְעִי וּמְצוּדָתִי אָתָּה</strong> (<em>kî-salʿî ûmĕṣûdātî ʾāttāh</em>, "For you are my rock and my fortress") — <em>selaʿ</em>: the cliff-face of rock (as in Ps 18:2). <strong>וּלְמַעַן שִׁמְךָ תַּנְחֵנִי וּתְנַהֲלֵנִי</strong> (<em>ûlĕmaʿan shimkā tanḥênî ûtĕnahălênî</em>, "lead me and guide me for your name\'s sake") — <em>nāḥāh</em>: to guide (as a shepherd leads); <em>nāhal</em>: to lead gently to water (as a shepherd leads to watering-places, Ps 23:2). The double shepherding verbs. <em>Lĕmaʿan shimkā</em>: "for the sake of your name" — God\'s own reputation as the motivation for his action.</p>',
    "4": '<p><strong>תּוֹצִיאֵנִי מֵרֶשֶׁת זוּ טָמְנוּ-לִי</strong> (<em>tôṣîʾênî mêreshet zû ṭāmĕnû-lî</em>, "Free me from the trap they have secretly set for me") — <em>reshet</em>: a net, a web — the hunting net laid for birds. <em>Ṭāman</em>: to hide, to conceal — the trap is secretly laid; the danger is not visible until it springs. The enemies as hunters who hide their devices.</p>',
    "5": '<p><strong>בְּיָדְךָ אַפְקִיד רוּחִי</strong> (<em>bĕyādĕkā ʾapqîd rûḥî</em>, "Into your hand I commit my spirit") — <em>pāqad</em> (hiphil: to entrust, to deposit for safekeeping — the legal term for depositing valuables into another\'s custody). <em>Rûaḥ</em>: spirit, breath — the animating life-force, the innermost self. Jesus quotes this exact verse from the cross in Luke 23:46 (LXX: <em>εἰς χεῖράς σου παρατίθεμαι τὸ πνεῦμά μου</em>), making his death the ultimate act of trust in the Father. In Jewish evening prayer this verse was used daily — the surrender of the breath-self to divine keeping through the night. <strong>פָּדִיתָה אוֹתִי יְהוָה אֵל אֱמֶת</strong> (<em>pādîtāh ʾôtî YHWH ʾêl ʾĕmet</em>, "you have redeemed me, LORD, faithful God") — <em>pādāh</em>: to ransom, to redeem.</p>',
    "6": '<p><strong>שָׂנֵאתִי הַשֹּׁמְרִים הַבְלֵי-שָׁוְא</strong> (<em>śānêtî hashomĕrîm habalê-shāwľ</em>, "I despise those who cling to worthless idols") — <em>shamar</em> (to keep, to cling to — here used for idol-devotion): the same verb for keeping commandments, deployed negatively for idol-adherence. <em>Habalê-shāwľ</em>: "vanities of emptiness" — <em>hebel</em> (breath/vanity — the word of Ecclesiastes) combined with <em>shāwľ</em> (worthlessness). The double-emptiness of idols. <strong>וַאֲנִי אֶל-יְהוָה בָּטָחְתִּי</strong> — the contrast: idol-clinging vs <em>bāṭaḥ</em> (trusting, leaning-on) that connects to the real.</p>',
    "7": '<p><strong>אָגִילָה וְאֶשְׂמְחָה בְּחַסְדֶּךָ</strong> (<em>ʾāgîlāh wĕʾesmĕḥāh bĕḥasdekā</em>, "I will be glad and rejoice in your steadfast love") — <em>gîl</em> and <em>śāmaḥ</em>: twin verbs of joy (same pairing as Ps 21:1). <em>Ḥesed</em>: covenant-loyalty love. <strong>אֲשֶׁר רָאִיתָ אֶת-עָנְיִי יָדַעְתָּ בְּצָרוֹת נַפְשִׁי</strong> — <em>rāʾāh</em>: to see; <em>yādaʿ</em>: to know experientially. God not only observed the distress from a distance but knew it from within, entering into the experience of the Psalmist\'s suffering.</p>',
    "8": '<p><strong>וְלֹא הִסְגַּרְתַּנִי בְּיַד-אוֹיֵב</strong> (<em>wĕlōʾ hisgartanî bĕyad-ʾôyêb</em>, "you did not hand me over to the enemy") — <em>sāgar</em> (hiphil: to deliver over as a prisoner): not handing over to the enemy. <strong>הֶעֱמַדְתָּ בַמֶּרְחָב רַגְלָי</strong> (<em>heʿĕmadtā bammerhāb raglāy</em>, "you set my feet in a wide-open place") — <em>merehāb</em> again (as in Ps 18:19; 4:1): salvation as liberation from the tight place (<em>ṣar</em>) into the wide space. God sets the feet in the open space — stable footing in an unconstrained environment.</p>',
    "9": '<p><strong>כִּי צָרָה-לִי עֵינִי כִּי נַפְשִׁי וּבִטְנִי</strong> (<em>kî ṣārāh-lî ʿênî kî napshî ûbiṭnî</em>, "my eye wastes with grief — my soul and my body too") — grief affects three registers: <em>ʿayin</em> (eye — what perceives the world), <em>nāpesh</em> (soul — the animating self), and <em>beṭen</em> (belly/body — the physical container). The eye that has wasted (<em>ʿāshash</em>: to shrink, to waste) is the eye that has wept until hollow.</p>',
    "10": '<p><strong>כִּי-כָלוּ בְיָגוֹן חַיַּי</strong> (<em>kî-kālû bĕyāgôn ḥayyay</em>, "For my life is exhausted by grief") — <em>kālāh</em>: to be completed/finished — life consumed by <em>yāgôn</em> (grief, sorrow). <strong>כָּשַׁל בַּעֲוֹנִי כֹחִי</strong> (<em>kāshal baʿăwōnî kōḥî</em>, "my strength fails because of my iniquity") — <em>kāshal</em>: to stumble, to stagger; <em>ʿāwôn</em>: iniquity, guilt. The confession that moral failure has physical consequences. <em>ʿAṣmôtay ʿāshōshû</em>: "my bones waste away" — the skeleton as deepest structural framework, now deteriorating.</p>',
    "11": '<p><strong>מִכָּל-צֹרְרַי הָיִיתִי חֶרְפָּה</strong> (<em>mikkol-ṣōrĕray hāyîtî ḥerpāh</em>, "Among all my enemies I am an object of scorn") — <em>ḥerpāh</em>: reproach, scorn, shame — the public shame that falls on the defeated and guilty. <strong>לִמְיֻדָּעַי מְאֹד</strong> — <em>mĕyuddāʿ</em> (those who know me): the people who knew the Psalmist in his prosperity now flee from him. Social abandonment accompanies disgrace — a condition that mirrors Jesus\' abandonment at the cross (Luke 23:49: "those who knew him stood at a distance").</p>',
    "12": '<p><strong>נִשְׁכַּחְתִּי כְּמֵת מִלֵּב</strong> (<em>nishkaḥtî kĕmêt millêb</em>, "I am as forgotten as a dead man") — <em>shākaḥ</em> (niphal: to be forgotten): the social death of being forgotten while still alive. <strong>הָיִיתִי כִּכְלִי אֹבֵד</strong> (<em>hāyîtî kiklî ʾōbêd</em>, "I have become like a shattered clay vessel") — <em>kelî</em>: vessel, instrument; <em>ʾōbêd</em>: perishing, destroyed. The broken pottery that has no further use and is discarded.</p>',
    "13": '<p><strong>כִּי שָׁמַעְתִּי דִּבַּת רַבִּים</strong> (<em>kî shāmaʿtî dibbat rabbîm</em>, "I hear the rumors of the many") — <em>dibbāh</em>: a whispering, a defamatory report — the gossip-network. <strong>מָגוֹר מִסָּבִיב</strong> (<em>māgôr missābîb</em>, "terror surrounds me") — <em>māgôr missābîb</em> is a Jeremian phrase (Jer 20:3, 10) — "terror on every side." Jeremiah uses it of himself and ironically gives it as the name of the priest who arrested him. Psalm and prophet share a vocabulary of total encirclement by threat.</p>',
    "14": '<p><strong>וַאֲנִי עָלֶיךָ בָטַחְתִּי יְהוָה</strong> (<em>waʾănî ʿālêkā bāṭaḥtî YHWH</em>, "But I trusted in you, LORD") — the <em>wĕʾănî</em> (but I) counter to all of vv9-13: despite abandonment, wasting, forgotten status, and surrounding terror — the Psalmist\'s orientation remains. <strong>אָמַרְתִּי אֱלֹהַי אָתָּה</strong> (<em>ʾāmartî ʾĕlōhay ʾāttāh</em>, "I said, \'You are my God\'") — the basic confession of covenant relationship: "my God." In the middle of catastrophe, the Psalmist speaks the relational claim.</p>',
    "15": '<p><strong>בְּיָדְךָ עִתֹּתָי</strong> (<em>bĕyādĕkā ʿittōtāy</em>, "My times are in your hand") — <em>ʿittîm</em>: times, seasons, appointed moments (plural of <em>ʿêt</em>: a fixed time). Every moment of vulnerability and opportunity held in the divine hand. Not fate but covenantal custody: the same hand into which the spirit was committed (v5) now holds all the moments of the life. <strong>הַצִּילֵנִי מִיַּד-אֹיְבַי</strong> (<em>haṣṣîlênî miyad-ʾōyĕbay</em>, "rescue me from my enemies") — the contest of which hand holds the Psalmist: the enemy\'s hand or the LORD\'s.</p>',
    "16": '<p><strong>הָאִירָה פָנֶיךָ עַל-עַבְדֶּךָ</strong> (<em>hāʾîrāh pānêkā ʿal-ʿabdekā</em>, "Make your face shine on your servant") — the priestly blessing of Num 6:25 ("the LORD make his face shine on you"): the illuminated divine face as the image of favorable presence. Contrast v7b: when the divine face was hidden, terror; when it shines, salvation. <strong>הוֹשִׁיעֵנִי בְחַסְדֶּךָ</strong> (<em>hôshîʿênî bĕḥasdekā</em>, "save me through your steadfast love") — grounded in <em>ḥesed</em>: rescue flows from covenant loyalty, not from the Psalmist\'s worthiness.</p>',
    "17": '<p><strong>יֵבֹשׁוּ רְשָׁעִים יִדְּמוּ לִשְׁאוֹל</strong> (<em>yêbōshû rĕshāʿîm yiddĕmû lishĕʾôl</em>, "let the wicked be ashamed — let them go silently down to Sheol") — <em>bûsh</em>: to be ashamed, put to shame (the social disgrace of public failure). <em>Dāmam</em>: to be silent — the silence of Sheol (as opposed to the singing of the rescued Psalmist in Ps 30:12). The reversal: the Psalmist, who was shamed and nearly silent, prays that the wicked get what they intended for him.</p>',
    "18": '<p><strong>תֵּאָלַמְנָה שִׂפְתֵי-שָׁקֶר</strong> (<em>tēʾālamĕnāh śiptê-shāqer</em>, "Let the lying lips be struck silent") — <em>ʾālam</em> (niphal: to be silenced, made mute): the lips that spoke the <em>dibbāh</em> (defamatory whispers) of v13 silenced. <strong>הַדֹּבְרוֹת עַל-צַדִּיק עָתָק בְּגַאֲוָה וָבוּז</strong> — <em>ʿātāq</em>: insolent, arrogant things; <em>gaʾăwāh</em>: pride; <em>bûz</em>: contempt. The attitude behind the speech: contempt for the righteous.</p>',
    "19": '<p><strong>מָה-רַב טוּבְךָ אֲשֶׁר-צָפַנְתָּ לִּירֵאֶיךָ</strong> (<em>māh-rab ṭûbĕkā ʾăsher-ṣāpantā lîrêʾêkā</em>, "How great is your goodness, which you have stored up for those who fear you") — <em>ṭôb</em>: goodness, good things. <em>Ṣāpan</em>: to store up, to hide away for safekeeping — the goodness of God held in reserve like treasure. <em>Lîrêʾêkā</em>: "for those who fear you" — <em>yirʾāh</em> (fear of God) as the qualifier of who receives it. <strong>פָּעַלְתָּ לַחֹסִים בָּךְ</strong> — <em>ḥāsāh</em> (participle: those who take refuge): the shelter-seekers for whom stored goodness is actualized.</p>',
    "20": '<p><strong>תַּסְתִּירֵם בְּסֵתֶר פָּנֶיךָ מֵרֻכְסֵי אִישׁ</strong> (<em>tastîrêm bĕsêter pānêkā mêrukhsê ʾîsh</em>, "In the shelter of your presence you hide them from human plots") — divine hiddenness now used positively: the <em>sêter pānim</em> (shelter of the face) as protective concealment. The very face whose hiding brought terror (v7) becomes the shelter of those who trust. <strong>תִּצְפְּנֵם בְּסֻכָּה מֵרִיב לְשֹׁנוֹת</strong> — hidden in the divine <em>sukkāh</em> (tabernacle/booth) from the quarreling of tongues — connecting to the Festival of Booths and divine dwelling among Israel.</p>',
    "21": '<p><strong>בָּרוּךְ יְהוָה כִּי-הִפְלִיא חַסְדּוֹ לִי</strong> (<em>bārûk YHWH kî-hipllîʾ ḥasdô lî</em>, "Praise the LORD, for he displayed his wonderful steadfast love to me") — <em>pālāʾ</em> (hiphil: to make wonderful, to act in a marvelous way): <em>ḥesed niphlāʾ</em> — love that operates beyond normal expectation. <strong>בְּעִיר מָצוֹר</strong> (<em>bĕʿîr māṣôr</em>, "when I was like a man in a besieged city") — <em>māṣôr</em>: siege — the city under siege as the situation of maximum danger. The Psalmist felt encircled (terror surrounds, v13) as a city under siege, yet from within that encirclement, divine love was displayed.</p>',
    "22": '<p><strong>וַאֲנִי אָמַרְתִּי בְחָפְזִי</strong> (<em>waʾănî ʾāmartî bĕḥāpĕzî</em>, "I said in my panic") — <em>ḥāpaz</em>: to flee in haste, to be panicked — a significant word: it appears in Exod 12:11 and Deut 16:3 for the hasty departure from Egypt (<em>bĕḥippāzôn</em>: "in haste"). The Psalmist\'s panic uses the exodus-departure word — his inner flight from composed trust. <strong>נִגְרַזְתִּי מִנֶּגֶד עֵינֶיךָ</strong> (<em>nigrăztî minneged ʿênêkā</em>, "I am cut off from your sight") — the feeling of severance from the divine gaze. <strong>שָׁמַעְתָּ קוֹל תַּחֲנוּנַי</strong> — the truth under the panic: the feeling was wrong; the hearing was real.</p>',
    "23": '<p><strong>אֶהֱבוּ אֶת-יְהוָה כָּל-חֲסִידָיו</strong> (<em>ʾehĕbû ʾet-YHWH kol-ḥăsîdāyw</em>, "Love the LORD, all you his faithful people!") — the move from individual testimony to community summons: the Psalmist\'s experience becomes the ground of exhortation to all the <em>ḥăsîdîm</em>. <strong>יְהוָה שֹׁמֵר אֱמוּנִים</strong> (<em>YHWH shōmêr ʾĕmûnîm</em>, "The LORD protects the faithful") — <em>ʾĕmûnîm</em>: the faithful ones (from <em>ʾāman</em>: to be firm, reliable, faithful). God watches over (<em>shāmar</em>) those characterized by <em>ʾemûnāh</em> (faithfulness).</p>',
    "24": '<p><strong>חִזְקוּ וְיַאֲמֵץ לְבַבְכֶם</strong> (<em>ḥizqû wĕyaʾămêṣ lĕbabkem</em>, "Be strong, and let your heart be courageous") — <em>ḥāzaq</em> (to be strong) and <em>ʾāmaṣ</em> (to be bold/courageous) — the same two verbs of the Deuteronomic commission: "Be strong and courageous" (<em>ḥazaq weʾĕmāṣ</em>, Deut 31:6-7; Josh 1:6-9). <strong>כָּל-הַמְיַחֲלִים לַיהוָה</strong> (<em>kol-hĕmĕyaḥălîm laYHWH</em>, "all you who hope in the LORD!") — <em>yāḥal</em>: to wait with expectation, to hope actively. The Psalm ends with the summons to those who are in the position the Psalmist was in at the beginning — in distress, waiting for the LORD to act.</p>',
  },
  "32": {
    "1": '<p><strong>מַשְׂכִּיל לְדָוִד</strong> (<em>maskîl lĕdāwid</em>) — the superscription identifies this as a <em>maskîl</em>: a teaching/wisdom psalm (from <em>śākal</em>: to be wise, to act prudently). It is the first of the seven traditional "Penitential Psalms." <strong>אַשְׁרֵי נְשׂוּי-פֶּשַׁע</strong> (<em>ʾashrê nĕśûy-peshaʿ</em>, "Blessed is the one whose transgression is forgiven") — <em>nāśāʾ</em> (passive participle: lifted, carried away): the transgression (<em>peshaʿ</em>: willful rebellion) is carried away like a burden. This is the language of Isa 53:4-6 (the Servant "bore our transgressions"). <strong>כְּסוּי חֲטָאָה</strong> (<em>kĕsûy ḥaṭṭāʾt</em>, "whose sin is covered") — <em>kāsāh</em>: to cover, to clothe — the sin hidden as if beneath a garment. Paul quotes vv1-2 in Rom 4:7-8 as proof that the OT itself taught justification by grace through non-reckoning of sin.</p>',
    "2": '<p><strong>אַשְׁרֵי אָדָם לֹא-יַחְשֹׁב יְהוָה לוֹ עָוֹן</strong> (<em>ʾashrê ʾādām lōʾ-yaḥshōb YHWH lô ʿāwôn</em>, "Blessed is the man to whom the LORD does not reckon iniquity") — <em>ḥāshab</em>: to reckon, to account, to calculate (an accounting term). Paul highlights this word in Rom 4:3-8 — it is the same word used for God "reckoning" righteousness to Abraham (Gen 15:6). The three terms of human guilt: <em>peshaʿ</em> (willful rebellion), <em>ḥaṭṭāʾt</em> (sin/missing the mark), <em>ʿāwôn</em> (iniquity/guilt). The three terms of divine remedy: carried away, covered, not-reckoned. <strong>וְאֵין בְּרוּחוֹ רְמִיָּה</strong> (<em>wĕʾên bĕrûḥô rĕmiyyāh</em>, "in whose spirit there is no deceit") — <em>rĕmiyyāh</em>: deceit, guile — the absence of self-deception (contrast v3-4).</p>',
    "3": '<p><strong>כִּי-הֶחֱשֵׁיתִי בָּלוּ עֲצָמָי</strong> (<em>kî-heḥĕshêtî bālû ʿăṣāmāy</em>, "When I kept silent about my sin, my bones wasted away") — <em>ḥāshah</em> (hiphil: to be silent) about the sin. <em>Bālāh</em>: to waste away, to deteriorate (as an old garment wears out). The bones as the structural framework: unconfessed guilt decays the deepest structural level. <strong>בְּשַׁאֲגָתִי כָּל-הַיּוֹם</strong> (<em>bĕshaʾăgātî kol-hayyôm</em>, "through my constant groaning") — <em>shaʾăgāh</em>: the roaring/groaning of an animal in distress (used of the lion\'s roar, Prov 19:12). Inarticulate bodily distress — the body expressing what the mouth refuses to confess.</p>',
    "4": '<p><strong>כִּי יוֹמָם וָלַיְלָה תִּכְבַּד עָלַי יָדֶךָ</strong> (<em>kî yômām wālaylāh tikkbad ʿālay yādekā</em>, "Day and night your hand pressed down on me") — <em>kābad</em>: to be heavy — the hand of God as a physical weight pressing on the unconfessed. Day and night without relief. <strong>נֶהְפַּךְ לְשַׁד-בְּחַרְבֹנֵי קָיִץ</strong> (<em>nehpak lĕshad-bĕḥarbōnê qāyiṣ</em>, "my strength dried up like moisture in the summer heat") — <em>shad</em>: moisture, sap (the liquid vitality of a plant); <em>ḥarbōnê qāyiṣ</em>: "summer drought conditions." Guilt as a drought that desiccates the inner life.</p>',
    "5": '<p><strong>חַטָּאתִי אוֹדִיעֲךָ</strong> (<em>ḥaṭṭāʾtî ʾôdîʿăkā</em>, "I made my sin known to you") — <em>yādaʿ</em> (hiphil: to cause to know): the Psalmist\'s act of confession makes the known-to-God sin also known from his own side. <strong>וַעֲוֹנִי לֹא-כִסִּיתִי</strong> (<em>waʿăwōnî lōʾ-kissîtî</em>, "did not hide my iniquity") — no longer self-concealing (contrast v3: the silent hiding). <strong>וְאַתָּה נָשָׂאתָ עֲוֹן חַטָּאתִי סֶלָה</strong> (<em>wĕʾattāh nāśāʾtā ʿāwôn ḥaṭṭāʾtî selāh</em>, "and you forgave the guilt of my sin") — <em>nāśāʾ</em>: the carrying-away of the iniquity (as in v1). The full arc in one verse: I made known → you carried away. The symmetry of confession and forgiveness.</p>',
    "6": '<p><strong>עַל-זֹאת יִתְפַּלֵּל כָּל-חָסִיד אֵלֶיךָ</strong> (<em>ʿal-zōʾt yitpallêl kol-ḥāsîd ʾêlêkā</em>, "Therefore let every faithful person pray to you") — the experience of vv3-5 becomes warrant for communal instruction: because confession works, every <em>ḥāsîd</em> should pray. <strong>לְעֵת מְצֹא</strong> (<em>lĕʿêt mĕṣōʾ</em>, "while you may still be found") — the urgency of the temporal window (<em>māṣāʾ</em>: to find — cf. Isa 55:6: "Seek the LORD while he may be found"). <strong>רַק לְשֵׁטֶף מַיִם רַבִּים</strong> (<em>raq lĕshêṭep māyim rabbîm</em>, "when the great floodwaters surge") — the <em>māyim rabbîm</em> (many waters) as chaos-force: prayer now offers protection when the floods come.</p>',
    "7": '<p><strong>אַתָּה סֵתֶר לִי</strong> (<em>ʾattāh sêter lî</em>, "You are my hiding place") — the <em>sêter</em> (shelter/concealment) used positively (as in Ps 31:20): God as the place of protected hiddenness. Not the hiding of unconfessed sin (v3) but the sheltering of the confessed and forgiven. <strong>רָנֵּי פַלֵּט תְּסוֹבְבֵנִי</strong> (<em>rannê palêṭ tĕsôbĕbênî</em>, "you surround me with songs of rescue") — <em>rannê palêṭ</em>: "shouts of rescue/deliverance" encircling the Psalmist. The surrounding terror (Ps 31:13) replaced by surrounding songs of rescue.</p>',
    "8": '<p><strong>אַשְׂכִּילְךָ וְאוֹרְךָ בְּדֶרֶךְ-זוּ תֵלֵךְ</strong> (<em>ʾaskîlĕkā wĕʾôrĕkā bĕderek-zû têlêk</em>, "I will instruct you and show you the way you should walk") — the subject shifts: this is now God speaking (or a wisdom teacher). <em>Śākal</em> (hiphil: to give insight, to make wise — the same root as <em>maskîl</em> in the superscription). The <em>maskîl</em> psalm demonstrates its didactic purpose: the God who forgave now instructs. <strong>אִיעֲצָה עָלֶיךָ עֵינִי</strong> (<em>îʿăṣāh ʿālêkā ʿênî</em>, "I will guide you with my eye on you") — the guiding eye as the attentive regard that keeps the led one on course.</p>',
    "9": '<p><strong>אַל-תִּהְיוּ כְּסוּס כְּפֶרֶד אֵין הָבִין</strong> (<em>ʾal-tihyû kĕsûs kĕpered ʾên hābîn</em>, "Do not be like a horse or mule that lacks understanding") — <em>bîn</em>: understanding (the same word as Ps 28:5: "they take no account"). The animal that cannot self-direct and must be controlled externally contrasts with the person who responds to the divine eye\'s guidance without requiring the bit (<em>beṣem</em>) and bridle (<em>resen</em>) of external compulsion.</p>',
    "10": '<p><strong>רַבִּים מַכְאוֹבִים לָרָשָׁע</strong> (<em>rabbîm makʾôbîm lārāshāʿ</em>, "The wicked have many sorrows") — the antithetical proverb: many pains (<em>makʾôb</em>: pain, sorrow) for the wicked vs. <strong>וְהַבּוֹטֵחַ בַּיהוָה חֶסֶד יְסוֹבְבֶנּוּ</strong> (<em>wĕhabbōṭêaḥ baYHWH ḥesed yĕsôbĕbennû</em>, "but steadfast love surrounds those who trust in the LORD") — surrounding <em>ḥesed</em> (covenant love) encircles those who <em>bāṭaḥ</em> (trust/lean). The contrast is spatial: many pains press on the wicked; covenant love encircles the trusting.</p>',
    "11": '<p><strong>שִׂמְחוּ בַיהוָה וְגִילוּ צַדִּיקִים</strong> (<em>śimḥû baYHWH wĕgîlû ṣaddîqîm</em>, "Be glad in the LORD and rejoice, you righteous people!") — <em>śāmaḥ</em> and <em>gîl</em> (the twin joy-verbs). <em>Ṣaddîqîm</em>: the righteous — here, those declared righteous through the confession-and-forgiveness process of vv1-5 (the Pauline reading: the righteous are the forgiven-and-not-reckoned-against). <strong>וְהַרְנִינוּ כָּל-יִשְׁרֵי-לֵב</strong> (<em>wĕharnînû kol-yishrê-lêb</em>, "Shout for joy, all who are upright in heart!") — <em>yāshar</em> (upright, straight-hearted): those whose inner orientation is without the deceit of v2b — the forgiven who no longer hide.</p>',
  },
  "33": {
    "1": '<p><strong>רַנְּנוּ צַדִּיקִים בַּיהוָה</strong> (<em>rannĕnû ṣaddîqîm baYHWH</em>, "Shout for joy in the LORD, you righteous!") — Psalm 33 has no superscription, making it anonymous — the only anonymous psalm in Book I (Ps 1-41) alongside Ps 1, 2, and 10. In the LXX it is attributed to David. The opening <em>rinnāh</em> (ringing shout of joy) picks up directly from Ps 32:11, continuing the exuberant sound. <strong>לַיְשָׁרִים נָאוָה תְהִלָּה</strong> (<em>layyĕshārîm nāwāh tĕhillāh</em>, "Praise is beautiful from those who are upright") — <em>nāwāh</em>: fitting, beautiful, appropriate. Praise is the congruous response of the <em>yĕshārîm</em> (upright ones).</p>',
    "2": '<p><strong>הוֹדוּ לַיהוָה בְּכִנּוֹר</strong> (<em>hôdû laYHWH bĕkinnôr</em>, "Praise the LORD with the lyre") — <em>kinnôr</em>: the lyre — David\'s instrument (1 Sam 16:23), the principal string instrument of ancient Israel. <strong>בְּנֵבֶל עָשׂוֹר זַמְּרוּ-לוֹ</strong> (<em>bĕnêbel ʿāśôr zammĕrû-lô</em>, "make music with the ten-stringed harp") — <em>nêbel</em>: the harp (larger than the <em>kinnôr</em>); <em>ʿāśôr</em>: "ten" (ten-stringed). The physicality of worship: instruments, voices, hands — all engaged.</p>',
    "3": '<p><strong>שִׁירוּ-לוֹ שִׁיר חָדָשׁ</strong> (<em>shîrû-lô shîr ḥādāsh</em>, "Sing him a new song") — <em>ḥādāsh</em>: new — the new song that corresponds to new saving acts (Ps 96:1; 98:1; 149:1; Isa 42:10; Rev 5:9; 14:3). Not novelty for its own sake but the appropriate response to fresh divine action. <strong>הֵיטִיבוּ נַגֵּן בִּתְרוּעָה</strong> (<em>hêṭîbû naggên bitĕrûʿāh</em>, "play with skill and shout for joy") — <em>yāṭab</em> (hiphil: to do well, to be skilled): excellence in musical execution as part of worship. <em>Tĕrûʿāh</em>: the war-shout/trumpet blast of victory — the same word as the shout at Jericho.</p>',
    "4": '<p><strong>כִּי-יָשָׁר דְּבַר-יְהוָה</strong> (<em>kî-yāshār dĕbar-YHWH</em>, "For the word of the LORD is right and true") — <em>yāshār</em>: straight, right, upright — the divine word as the standard of uprightness. <strong>וְכָל-מַעֲשֵׂהוּ בֶּאֱמוּנָה</strong> (<em>wĕkol-maʿăśêhû beʾĕmûnāh</em>, "all his works are done in faithfulness") — <em>ʾĕmûnāh</em>: faithfulness, reliability, consistency. The word is straight; the works are faithful. This verse prepares for vv6-9 by establishing that the creative word operates in faithfulness.</p>',
    "5": '<p><strong>אֹהֵב צְדָקָה וּמִשְׁפָּט</strong> (<em>ʾōhêb ṣĕdāqāh ûmishpāṭ</em>, "He loves righteousness and justice") — the pair <em>ṣĕdāqāh</em> (righteousness/right-standing) and <em>mishpāṭ</em> (justice/judgment) is the foundational moral vocabulary of the Hebrew prophets (Amos 5:24; Mic 6:8; Isa 5:7). God\'s love (<em>ʾāhab</em>) for these qualities expresses his character. <strong>חֶסֶד יְהוָה מָלְאָה הָאָרֶץ</strong> (<em>ḥesed YHWH māleʾāh hāʾāreṣ</em>, "the earth is full of the LORD\'s steadfast love") — the <em>ḥesed</em> of YHWH fills the earth — not private and limited to Israel but overflowing into the whole created order.</p>',
    "6": '<p><strong>בִּדְבַר יְהוָה שָׁמַיִם נַעֲשׂוּ</strong> (<em>bidĕbar YHWH shāmayim naʿăśû</em>, "The heavens were made by the word of the LORD") — <em>dĕbar YHWH</em>: the word of the LORD — the creative speech of Gen 1 ("and God said…"). The heavens are the product of divine speech. <strong>וּבְרוּחַ פִּיו כָּל-צְבָאָם</strong> (<em>ûbĕrûaḥ pîw kol-ṣĕbāʾām</em>, "all their host by the breath of his mouth") — <em>rûaḥ pîw</em>: "breath/spirit of his mouth" — the divine breath that is both the wind hovering over the waters (Gen 1:2) and the speech-breath issuing creative words. John 1:1-3 develops this <em>dĕbar YHWH</em> theology christologically: the Word (<em>Logos</em>) through whom all things were made is the pre-existent Son.</p>',
    "7": '<p><strong>כֹּנֵס כַּנֵּד מֵי הַיָּם</strong> (<em>kōnês kannêd mê hayyām</em>, "He gathers the sea\'s waters like a heap") — <em>kānās</em>: to gather, to pile up; <em>nêd</em>: a heap, a mound. This echoes the Exodus sea-crossing: "The waters piled up; the surging waters stood firm like a wall" (Exod 15:8, the same word <em>nêd</em>). God\'s creative ordering of the waters is the same power as the Exodus rescue. <strong>נֹתֵן בְּאֹצָרוֹת תְּהוֹמוֹת</strong> (<em>nōtên bĕʾōṣārôt tĕhômôt</em>, "he stores the deep in reservoirs") — <em>tĕhôm</em>: the deep (Gen 1:2); <em>ʾōṣār</em>: treasury, storehouse. God stores the chaotic deep as if it were treasure in a vault — sovereignty over the primordial chaos.</p>',
    "8": '<p><strong>יִירְאוּ מֵיְהוָה כָּל-הָאָרֶץ</strong> (<em>yîrĕʾû mêYHWH kol-hāʾāreṣ</em>, "Let all the earth fear the LORD") — the universal summons to <em>yirʾāh</em> (reverence/fear): not Israel alone but all the earth. The ground for universal reverence is given in vv6-7: the creator of the heavens and sovereign over the deep deserves universal acknowledgment. <strong>מִמֶּנּוּ יָגוּרוּ כָּל-יֹשְׁבֵי תֵבֵל</strong> (<em>mimmennu yāgûrû kol-yōshĕbê têbêl</em>, "let all who live in the world stand in awe of him") — <em>têbêl</em>: the inhabited world — the specifically human-populated earth.</p>',
    "9": '<p><strong>כִּי הוּא אָמַר וַיֶּהִי</strong> (<em>kî hûʾ ʾāmar wayyehî</em>, "For he spoke, and it came to be") — the fiat-creation formula: <em>ʾāmar</em> (he spoke) and <em>yehî</em> (and it was) — the Gen 1 pattern: "And God said… and there was." The word is causally sufficient for existence: no further mechanism needed. <strong>הוּא-צִוָּה וַיַּעֲמֹד</strong> (<em>hûʾ-ṣiwwāh wayyaʿămōd</em>, "he commanded, and it stood firm") — <em>ṣiwwāh</em>: to command (the same word for divine commandments); <em>ʿāmad</em>: to stand, to endure. What the divine command calls into being "stands" — the command is the foundation of created permanence.</p>',
    "10": '<p><strong>יְהוָה הֵפִיר עֲצַת-גּוֹיִם</strong> (<em>YHWH hêpîr ʿăṣat-gôyim</em>, "The LORD thwarts the purposes of the nations") — <em>pārar</em> (hiphil: to break, to frustrate, to make void): the divine frustration of human plans. <em>ʿĒṣāh</em>: counsel, plan, strategy. <strong>הֵנִיא מַחְשְׁבוֹת עַמִּים</strong> (<em>hênîʾ maḥshĕbôt ʿammîm</em>, "he brings the plans of the peoples to nothing") — <em>maḥshāb</em>: thought, plan (from <em>ḥāshab</em>: to reckon — the same accounting root as Ps 32:2). The nations\' reckonings are un-reckoned by the LORD; their plans dissolve before the divine purpose (v11).</p>',
    "11": '<p><strong>עֲצַת יְהוָה לְעוֹלָם תַּעֲמֹד</strong> (<em>ʿăṣat YHWH lĕʿôlām taʿămōd</em>, "The counsel of the LORD stands forever") — the same word <em>ʿēṣāh</em> (counsel/purpose) used for the nations\' plans in v10, now applied to the divine plan. The contrast is permanence: the nations\' <em>ʿēṣāh</em> is frustrated; the LORD\'s <em>ʿēṣāh</em> stands (<em>ʿāmad</em>) forever — the same verb as v9 ("it stood firm"). <strong>מַחְשְׁבוֹת לִבּוֹ לְדֹר וָדֹר</strong> (<em>maḥshĕbôt libbô lĕdōr wādōr</em>, "the purposes of his heart through all generations") — the deep interior intention of God persists generation after generation.</p>',
    "12": '<p><strong>אַשְׁרֵי הַגּוֹי אֲשֶׁר-יְהוָה אֱלֹהָיו</strong> (<em>ʾashrê haggôy ʾăsher-YHWH ʾĕlōhāyw</em>, "Blessed is the nation whose God is the LORD") — the <em>ʾashrê</em> beatitude applied to a nation (<em>gôy</em>): collective blessedness. <strong>הָעָם בָּחַר לְנַחֲלָה לוֹ</strong> (<em>hāʿām bāḥar lĕnaḥălāh lô</em>, "the people he has chosen as his own possession") — <em>bāḥar</em>: to choose (the election vocabulary of Deut 7:6); <em>naḥălāh</em>: inheritance, possession. The chosen people as the LORD\'s own inheritance. 1 Pet 2:9 applies this election-language to the church: "a chosen people… God\'s special possession."</p>',
    "13": '<p><strong>מִשָּׁמַיִם הִבִּיט יְהוָה</strong> (<em>mishshāmayim hibbîṭ YHWH</em>, "The LORD looks down from heaven") — <em>nābaṭ</em> (hiphil: to look, to gaze intently): not a casual glance but deliberate, attentive observation from the divine vantage above the heavens. <strong>רָאָה אֶת-כָּל-בְּנֵי הָאָדָם</strong> (<em>rāʾāh ʾet-kol-bĕnê hāʾādām</em>, "he observes all humanity") — <em>bĕnê hāʾādām</em>: "sons of Adam" — humanity as the descendants of the first human. Universal scope: not Israel specifically but all of Adam\'s offspring.</p>',
    "14": '<p><strong>מִמְּכוֹן-שִׁבְתּוֹ הִשְׁגִּיחַ</strong> (<em>mimmĕkôn-shībtô hishgîaḥ</em>, "from his dwelling place he surveys") — <em>shāgaḥ</em> (hiphil: to look attentively, to survey): the patient, comprehensive gaze. <em>Mĕkôn-shîbtô</em>: "the established/fixed place of his sitting" — the heavenly throne as the permanent vantage point. <strong>אֶל כָּל-יֹשְׁבֵי הָאָרֶץ</strong> (<em>ʾel kol-yōshĕbê hāʾāreṣ</em>, "all who live on the earth") — every earthly inhabitant within the divine field of vision.</p>',
    "15": '<p><strong>הַיֹּצֵר יַחַד לִבָּם</strong> (<em>hayyōṣêr yaḥad libbām</em>, "he who forms the hearts of all") — <em>yāṣar</em>: to form, to shape (as a potter shapes clay — Gen 2:7: "the LORD God formed the human from the dust"). <em>Yaḥad libbām</em>: "all their hearts together" — the divine potter who formed each individual heart also knows what he has made. <strong>הַמֵּבִין אֶל-כָּל-מַעֲשֵׂיהֶם</strong> (<em>hammêbîn ʾel-kol-maʿăśêhem</em>, "and considers everything they do") — <em>bîn</em>: to understand, to discern (Ps 28:5; 32:9). The one who made the hearts understands every deed those hearts produce.</p>',
    "16": '<p><strong>אֵין-הַמֶּלֶךְ נוֹשָׁע בְּרָב-חָיִל</strong> (<em>ʾên-hammelek nôshāʿ bĕrab-ḥāyil</em>, "No king is saved by the size of his army") — political theology: military might (<em>ḥāyil</em>: valor, army) does not determine victory. <em>Nôshāʿ</em> (niphal passive: saved/rescued): the king himself is not the saver but the one who needs saving — and the size of his forces does not guarantee his rescue.</p>',
    "17": '<p><strong>שֶׁקֶר הַסּוּס לִתְשׁוּעָה</strong> (<em>sheqer hassûs litshûʿāh</em>, "A horse is a vain hope for victory") — <em>sheqer</em>: falsehood, deception — the horse as a liar in the sense of promising what it cannot deliver. The war-horse (<em>sûs</em>) was the cutting-edge military technology of the ancient world (chariot warfare); Ps 20:7 contrasted horse-trust with name-of-the-LORD trust. <strong>וּבְרֹב חֵילוֹ לֹא יְמַלֵּט</strong> (<em>ûbĕrōb ḥêlô lōʾ yĕmallêṭ</em>, "its great power cannot bring rescue") — <em>mālat</em> (piel: to cause to escape, to rescue): the horse\'s great strength cannot produce escape.</p>',
    "18": '<p><strong>הִנֵּה עֵין יְהוָה אֶל-יְרֵאָיו</strong> (<em>hinnêh ʿên YHWH ʾel-yĕrêʾāyw</em>, "The eye of the LORD is on those who fear him") — the divine eye that surveys all humanity (v13-14) is specifically protective toward those who fear him. <em>Yĕrêʾāyw</em>: those who fear him — the relationship vocabulary. <strong>לַמְיַחֲלִים לְחַסְדּוֹ</strong> (<em>lamĕyaḥălîm lĕḥasdô</em>, "on those who hope in his steadfast love") — <em>yāḥal</em>: to wait with expectation (the same word as the closing line of Ps 31:24); <em>ḥesed</em>: covenant love. The eye is on those whose hope is directed toward the LORD\'s own <em>ḥesed</em> — not toward their own resources (vv16-17).</p>',
    "19": '<p><strong>לְהַצִּיל מִמָּוֶת נַפְשָׁם</strong> (<em>lĕhaṣṣîl mimmāwet napshām</em>, "to rescue them from death") — the purpose of the divine eye: rescue from death. <em>Nāṣal</em> (hiphil: to snatch away, rescue). <em>Nāpesh</em>: the living self — the whole person rescued from death. <strong>וּלְחַיּוֹתָם בָּרָעָב</strong> (<em>ûlĕḥayyôtām bārāʿāb</em>, "to keep them alive in famine") — concrete provision: survival in famine (<em>rāʿāb</em>). God\'s providential care is not abstract — it reaches into the physical need for food.</p>',
    "20": '<p><strong>נַפְשֵׁנוּ חִכְּתָה לַיהוָה</strong> (<em>napshênû ḥikkĕtāh laYHWH</em>, "We wait for the LORD") — the communal voice: "our soul has waited" (<em>ḥikkāh</em>: to wait, to be patient — intensive waiting). The individual hope of v18 now becomes the communal confession. <strong>עֶזְרֵנוּ וּמָגִנֵּנוּ הוּא</strong> (<em>ʿezrênû ûmāginnênû hûʾ</em>, "he is our help and our shield") — <em>ʿezer</em>: helper (Ps 30:10); <em>māgên</em>: shield (Ps 28:7). The communal declaration: "he is" — the predicate of identity, not petition. Already the help; already the shield.</p>',
    "21": '<p><strong>כִּי-בוֹ יִשְׂמַח לִבֵּנוּ</strong> (<em>kî-bô yiśmaḥ libbênû</em>, "Our hearts are glad in him") — <em>śāmaḥ</em>: rejoice, be glad; the gladness is "in him" (<em>bô</em>) — not in circumstances but in the person of the LORD who is the help and shield. <strong>כִּי בְשֵׁם קָדְשׁוֹ בָטָחְנוּ</strong> (<em>kî bĕshêm qodshô bāṭāḥnû</em>, "for we trust in his holy name") — <em>bāṭaḥ</em>: to trust, to lean on (the persistent trust-verb of this cluster of psalms). The holy name as the ground of trust.</p>',
    "22": '<p><strong>יְהִי-חַסְדְּךָ יְהוָה עָלֵינוּ</strong> (<em>yĕhî-ḥasdĕkā YHWH ʿālênû</em>, "Let your steadfast love, LORD, rest on us") — the jussive closing prayer: may the <em>ḥesed</em> that belongs to the LORD come to rest on the community. The psalm ends with the same word that saturated it — <em>ḥesed</em> (vv5, 18, 22). The whole psalm is a meditation on divine <em>ḥesed</em> as the ground of creation (v5), the object of hope (v18), and the content of the closing prayer. <strong>כַּאֲשֶׁר יִחַלְנוּ לָךְ</strong> (<em>kaʾăsher yiḥalnû lāk</em>, "as we have placed our hope in you") — <em>yāḥal</em>: the same hope-waiting of v18 and Ps 31:24. The closing prayer links the <em>ḥesed</em> to the hoping: may covenant love rest on us in proportion to the hope we have placed in you.</p>',
  },
}

def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    for ch in range(28, 34):
        print(f'  ch{ch}: {len(existing.get(str(ch), {}))} verses')
    print('Psalms 28-33 mkt-original written.')

if __name__ == '__main__':
    main()
